-- Create a new table for detailed protocol checklist items
CREATE TABLE public.protocol_checklist_items (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  checklist_item_id TEXT NOT NULL UNIQUE,
  block TEXT NOT NULL,
  block_order INTEGER NOT NULL,
  education_level_do BOOLEAN NOT NULL DEFAULT false,
  education_level_noo BOOLEAN NOT NULL DEFAULT false,
  education_level_oo BOOLEAN NOT NULL DEFAULT false,
  education_level_soo BOOLEAN NOT NULL DEFAULT false,
  topic TEXT NOT NULL,
  topic_order INTEGER NOT NULL,
  subtopic TEXT NOT NULL,
  subtopic_order INTEGER NOT NULL,
  description TEXT NOT NULL,
  score_0_label TEXT,
  score_1_label TEXT,
  weight DECIMAL(3,1) NOT NULL DEFAULT 1.0,
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),
  updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.protocol_checklist_items ENABLE ROW LEVEL SECURITY;

-- Create policies
CREATE POLICY "Protocol checklist items are viewable by everyone" 
ON public.protocol_checklist_items 
FOR SELECT 
USING (true);

CREATE POLICY "Users can insert protocol checklist items" 
ON public.protocol_checklist_items 
FOR INSERT 
WITH CHECK (true);

CREATE POLICY "Users can update protocol checklist items" 
ON public.protocol_checklist_items 
FOR UPDATE 
USING (true);

-- Add trigger for timestamps
CREATE TRIGGER update_protocol_checklist_items_updated_at
BEFORE UPDATE ON public.protocol_checklist_items
FOR EACH ROW
EXECUTE FUNCTION public.update_updated_at_column();

